def get_animethemes_stream_url(filename):
    """Get streaming URL for a theme from AnimThemes using the filename as basename."""
    return f"https://v.animethemes.moe/{filename}"

def load_cache_metadata():
    """Load cache metadata from JSON file."""
    global cache_metadata
    try:
        if os.path.exists(CACHE_METADATA_FILE):
            with open(CACHE_METADATA_FILE, 'r', encoding='utf-8') as f:
                cache_metadata = json.load(f)
        else:
            cache_metadata = {}
    except Exception as e:
        print(f"Error loading cache metadata: {e}")
        cache_metadata = {}

def save_cache_metadata():
    """Save cache metadata to JSON file."""
    try:
        os.makedirs(os.path.dirname(CACHE_METADATA_FILE), exist_ok=True)
        with open(CACHE_METADATA_FILE, 'w', encoding='utf-8') as f:
            json.dump(cache_metadata, f, indent=2)
    except Exception as e:
        print(f"Error saving cache metadata: {e}")

def get_cache_size_mb():
    """Get current cache size in MB."""
    total_size = 0
    for filename, metadata in cache_metadata.items():
        total_size += metadata.get('size', 0)
    return total_size / (1024 * 1024)  # Convert to MB

def get_cached_file_path(filename):
    """Get the path to a cached file if it exists."""
    # Check if we have it in metadata with the path
    if filename in cache_metadata:
        rel_path = cache_metadata[filename].get('path', filename)
        cache_path = os.path.join(THEMES_CACHE_FOLDER, rel_path)
        if os.path.exists(cache_path):
            return cache_path
    
    # Fallback: check flat structure for legacy cached files
    cache_path = os.path.join(THEMES_CACHE_FOLDER, filename)
    if os.path.exists(cache_path):
        return cache_path
    
    return None

def evict_cache_for_size(needed_size_bytes):
    """Evict least-used files from cache to make room for new download.
    
    Args:
        needed_size_bytes: Size needed in bytes
        
    Returns:
        True if enough space was freed, False otherwise
    """
    global cache_metadata
    
    # Calculate current cache size in bytes
    current_size = sum(meta.get('size', 0) for meta in cache_metadata.values())
    cache_limit_bytes = themes_cache_size * 1024 * 1024
    
    if current_size + needed_size_bytes <= cache_limit_bytes:
        return True  # Already have space
    
    # Build list of cached files with their timestamps
    # Priority: oldest last_played first
    cached_files = []
    for filename, meta in cache_metadata.items():
        cached_files.append({
            'filename': filename,
            'size': meta.get('size', 0),
            'play_count': meta.get('play_count', 0),
            'last_played': meta.get('last_played', ''),
        })
    
    # Sort by last_played (ascending/oldest first)
    cached_files.sort(key=lambda x: x['last_played'])
    
    # Remove files until we have enough space
    space_needed = current_size + needed_size_bytes - cache_limit_bytes
    space_freed = 0
    
    for file_info in cached_files:
        if space_freed >= space_needed:
            break
        
        filename = file_info['filename']
        # Use stored path from metadata
        rel_path = cache_metadata.get(filename, {}).get('path', filename)
        cache_path = os.path.join(THEMES_CACHE_FOLDER, rel_path)
        
        try:
            if os.path.exists(cache_path):
                os.remove(cache_path)
                
                # Clean up empty directories
                cache_dir = os.path.dirname(cache_path)
                try:
                    while cache_dir != THEMES_CACHE_FOLDER and os.path.exists(cache_dir):
                        if not os.listdir(cache_dir):  # Directory is empty
                            os.rmdir(cache_dir)
                            cache_dir = os.path.dirname(cache_dir)
                        else:
                            break
                except:
                    pass  # Ignore cleanup errors
                
                # Only count freed space if file actually existed and was deleted
                space_freed += file_info['size']
                del cache_metadata[filename]
            else:
                # File doesn't exist but is in metadata - clean up metadata only
                del cache_metadata[filename]
        except Exception as e:
            print(f"Error evicting {filename}: {e}")
    
    save_cache_metadata()
    return space_freed >= space_needed

def update_cache_play_count(filename):
    """Update play count and last played timestamp for a cached file."""
    if filename in cache_metadata:
        cache_metadata[filename]['play_count'] = cache_metadata[filename].get('play_count', 0) + 1
        cache_metadata[filename]['last_played'] = datetime.now().isoformat()
        save_cache_metadata()

def _download_animethemes_file_to_path(filename, dest_path, progress_callback=None):
    """Core download logic for AnimThemes files.
    
    Args:
        filename: Name of the file to download
        dest_path: Full destination path
        progress_callback: Optional callback(downloaded_mb, total_mb) for progress updates
        
    Returns:
        True if successful, False otherwise
    """
    try:
        url = get_animethemes_stream_url(filename)
        headers = {'User-Agent': f'GuessTheAnime/{APP_VERSION} (https://github.com/ualkotob/guess-the-anime-playlist-tool)'}
        response = requests.get(url, stream=True, timeout=30, headers=headers)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        downloaded = 0
        
        # Write to file with progress tracking
        with open(dest_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                # Check for cancellation
                if filename in download_cancel_flags and download_cancel_flags[filename]:
                    print(f"Download cancelled: {filename}")
                    return False
                
                if chunk:
                    f.write(chunk)
                    downloaded += len(chunk)
                    if progress_callback and total_size > 0:
                        mb_downloaded = downloaded / 1024 / 1024
                        mb_total = total_size / 1024 / 1024
                        progress_callback(mb_downloaded, mb_total)
        
        return True
    except Exception as e:
        print(f"Download error for {filename}: {e}")
        return False

def download_animethemes_file(filename, button=None):
    """Download an AnimThemes file and save it to directory/year/season/filename structure."""
    def update_button(text):
        if button and isinstance(button, tk.Button):
            try:
                button.config(text=text)
            except:
                pass
    
    def do_download():
        try:
            update_button("Starting...")
            
            # Get metadata to determine season/year
            data = get_metadata(filename)
            season_str = data.get("season", "")
            
            # Parse season string (format: "Season Year", e.g., "Winter 2024")
            if season_str and season_str != "N/A":
                parts = season_str.split()
                if len(parts) >= 2:
                    season = parts[0]  # e.g., "Winter"
                    year = parts[1]    # e.g., "2024"
                else:
                    season = "Unknown"
                    year = "Unknown"
            else:
                season = "Unknown"
                year = "Unknown"
            
            # Create directory structure: directory/year/season/
            if directory:
                dest_dir = os.path.join(directory, year, season)
            else:
                dest_dir = os.path.join(year, season)
            
            os.makedirs(dest_dir, exist_ok=True)
            dest_path = os.path.join(dest_dir, filename)
            
            # Download using core function
            update_button("Downloading...")
            
            def progress_callback(mb_downloaded, mb_total):
                update_button(f"{mb_downloaded:.1f}/{mb_total:.1f} MB")
            
            success = _download_animethemes_file_to_path(filename, dest_path, progress_callback)
            
            if not success:
                update_button("Error")
                messagebox.showerror("Download Error", f"Failed to download {filename}")
                return
            
            # Update directory_files to include the new file
            directory_files[filename] = dest_path
            
            # Success message
            filesize_mb = os.path.getsize(dest_path) / 1024 / 1024
            update_button(f"✓ {filesize_mb:.1f} MB")
            print(f"Downloaded {filename} to {dest_path}")
            
            # Refresh displays
            if list_loaded == "playlist":
                root.after(100, lambda: show_playlist(True))
            
            # Refresh file actions display to show local file actions instead of download
            if currently_playing and currently_playing.get("filename") == filename:
                root.after(100, lambda: update_extra_metadata())
            
        except Exception as e:
            update_button("Error")
            print(f"Download error for {filename}: {e}")
            messagebox.showerror("Download Error", f"Failed to download {filename}:\n\n{str(e)}")
    
    # Start download in background thread
    threading.Thread(target=do_download, daemon=True).start()

def move_cached_file_to_directory(filename, button=None):
    """Move a cached file to the proper directory/year/season structure.
    
    Args:
        filename: Name of the file to move
        button: Optional button widget to update with status
    """
    def update_button(text):
        if button and isinstance(button, tk.Button):
            try:
                button.config(text=text)
            except:
                pass
    
    def do_move():
        try:
            update_button("Moving...")
            
            # Get cached file path
            cached_path = get_cached_file_path(filename)
            if not cached_path:
                update_button("Not Cached")
                messagebox.showerror("Error", f"File not found in cache: {filename}")
                return
            
            # Get metadata to determine season/year
            data = get_metadata(filename)
            season_str = data.get("season", "")
            
            # Parse season string (format: "Season Year", e.g., "Winter 2024")
            if season_str and season_str != "N/A":
                parts = season_str.split()
                if len(parts) >= 2:
                    season = parts[0]  # e.g., "Winter"
                    year = parts[1]    # e.g., "2024"
                else:
                    season = "Unknown"
                    year = "Unknown"
            else:
                season = "Unknown"
                year = "Unknown"
            
            # Create directory structure: directory/year/season/
            if directory:
                dest_dir = os.path.join(directory, year, season)
            else:
                dest_dir = os.path.join(year, season)
            
            os.makedirs(dest_dir, exist_ok=True)
            dest_path = os.path.join(dest_dir, filename)
            
            # Move the file from cache to directory
            shutil.move(cached_path, dest_path)
            
            # Clean up empty cache directories
            cache_dir = os.path.dirname(cached_path)
            try:
                while cache_dir != THEMES_CACHE_FOLDER and os.path.exists(cache_dir):
                    if not os.listdir(cache_dir):  # Directory is empty
                        os.rmdir(cache_dir)
                        cache_dir = os.path.dirname(cache_dir)
                    else:
                        break
            except:
                pass  # Ignore cleanup errors
            
            # Update directory_files
            directory_files[filename] = dest_path
            
            # Remove from cache metadata
            if filename in cache_metadata:
                del cache_metadata[filename]
                save_cache_metadata()
            
            # Success
            filesize_mb = os.path.getsize(dest_path) / 1024 / 1024
            update_button(f"✓ {filesize_mb:.1f} MB")
            print(f"Moved {filename} from cache to {dest_path}")
            
            # Refresh displays
            if list_loaded == "playlist":
                root.after(100, lambda: show_playlist(True))
            
            # Refresh file actions display to show local file actions
            if currently_playing and currently_playing.get("filename") == filename:
                root.after(100, lambda: update_extra_metadata())
            
        except Exception as e:
            update_button("Error")
            print(f"Move error for {filename}: {e}")
            messagebox.showerror("Move Error", f"Failed to move {filename}:\n\n{str(e)}")
    
    # Start move in background thread
    threading.Thread(target=do_move, daemon=True).start()

def create_download_popup(filename):
    """Create a progress popup window for a downloading file.
    
    Args:
        filename: Name of the file being downloaded
        
    Returns:
        Dictionary with popup and widget references
    """
    popup = tk.Toplevel(root)
    popup.overrideredirect(True)  # Borderless window
    popup.attributes('-topmost', True)  # Keep on top
    popup.transient(root)
    
    # Configure colors
    bg_color = "#1e1e1e"  # gray12
    fg_color = "white"
    border_color = "#444"
    button_bg = "#333"
    button_hover = "#555"
    
    # Main frame with border
    main_frame = tk.Frame(popup, bg=border_color, padx=2, pady=2)
    main_frame.pack(fill="both", expand=True)
    
    inner_frame = tk.Frame(main_frame, bg=bg_color)
    inner_frame.pack(fill="both", expand=True)
    
    # Title label
    title_label = tk.Label(inner_frame, text="Loading theme...", font=("Arial", 12, "bold"), 
                          bg=bg_color, fg=fg_color)
    title_label.pack(pady=(15, 5))
    
    # Filename label (truncate if too long)
    # display_name = filename if len(filename) <= 45 else filename[:42] + "..."
    # filename_label = tk.Label(inner_frame, text=display_name, font=("Arial", 11), 
    #                          bg=bg_color, fg="#aaa")
    # filename_label.pack(pady=(0, 10))
    
    # Progress bar with custom style
    style = ttk.Style()
    style.theme_use('default')
    style.configure("Download.Horizontal.TProgressbar", 
                   troughcolor='#333', 
                   background='#0078d7',
                   bordercolor=bg_color,
                   lightcolor='#0078d7',
                   darkcolor='#0078d7')
    
    progress_bar = ttk.Progressbar(inner_frame, length=450, mode='determinate', 
                                  style="Download.Horizontal.TProgressbar")
    progress_bar.pack(pady=(0, 10), padx=20, ipady=8)
    
    # Status label (bigger text)
    status_label = tk.Label(inner_frame, text="Starting download...", font=("Arial", 11), 
                           bg=bg_color, fg=fg_color)
    status_label.pack(pady=(0, 5))
    
    # Button frame
    button_frame = tk.Frame(inner_frame, bg=bg_color)
    button_frame.pack(pady=(0, 10))
    
    # Cancel button
    def on_cancel():
        cancel_download(filename)
    
    cancel_button = tk.Button(button_frame, text="Cancel", font=("Arial", 10), 
                             bg=button_bg, fg=fg_color, activebackground=button_hover,
                             command=on_cancel, width=10, relief=tk.FLAT)
    cancel_button.pack(side=tk.LEFT, padx=5)
    
    # Retry button
    def on_retry():
        retry_download(filename)
    
    retry_button = tk.Button(button_frame, text="Retry", font=("Arial", 10), 
                            bg=button_bg, fg=fg_color, activebackground=button_hover,
                            command=on_retry, width=10, relief=tk.FLAT)
    retry_button.pack(side=tk.LEFT, padx=5)
    
    # Center the popup
    popup.update_idletasks()
    width = 500
    height = 170
    x = (popup.winfo_screenwidth() // 2) - (width // 2)
    y = (popup.winfo_screenheight() // 2) - (height // 2)
    popup.geometry(f"{width}x{height}+{x}+{y}")
    
    # Force the window to display
    popup.deiconify()
    popup.lift()
    popup.focus_force()
    popup.update()
    
    return {
        'popup': popup,
        'progress_bar': progress_bar,
        'status_label': status_label,
        'cancel_button': cancel_button,
        'retry_button': retry_button
    }

def cancel_download(filename):
    """Cancel an active download.
    
    Args:
        filename: Name of the file being downloaded
    """
    global download_cancel_flags, active_downloads, pending_play_queue
    
    if filename in active_downloads:
        # Set cancel flag
        download_cancel_flags[filename] = True
        print(f"Cancelling download: {filename}")
        
        # Remove from pending play queue if present
        if filename in pending_play_queue:
            pending_play_queue.pop(filename, None)
        
        # The download thread will check this flag and exit
        # The cleanup will happen in the download thread's finally block

def retry_download(filename):
    """Retry a failed or cancelled download.
    
    Args:
        filename: Name of the file to retry downloading
    """
    global download_cancel_flags, download_progress, pending_play_queue
    
    # Preserve pending play info if it exists (so file plays after retry completes)
    pending_play_info = pending_play_queue.get(filename)
    
    # If currently downloading, cancel it first
    if filename in active_downloads:
        print(f"Stopping current download to retry: {filename}")
        cancel_download(filename)
        
        # Wait a moment for cancellation to complete, then start new download
        def start_retry():
            # Clear any cancel flags
            download_cancel_flags.pop(filename, None)
            
            # Restore pending play queue entry if it existed
            if pending_play_info:
                pending_play_queue[filename] = pending_play_info
                # Reset start time so timeout doesn't trigger immediately
                pending_play_queue[filename]['start_time'] = time.time()
            
            # Start new download
            download_to_cache(filename, silent=False)
            print(f"Retrying download: {filename}")
        
        # Schedule retry after 500ms to allow cancellation to complete
        root.after(500, start_retry)
    else:
        # Not downloading, start immediately
        # Clear any cancel flags
        download_cancel_flags.pop(filename, None)
        
        # Close existing popup if present
        if filename in download_progress:
            popup_ref = download_progress[filename].get('popup')
            if popup_ref:
                try:
                    popup_ref.destroy()
                except:
                    pass
            download_progress.pop(filename, None)
        
        # Restore or create pending play queue entry
        if pending_play_info:
            pending_play_queue[filename] = pending_play_info
            # Reset start time so timeout doesn't trigger immediately
            pending_play_queue[filename]['start_time'] = time.time()
        else:
            # Create a new pending play entry if one didn't exist
            # (This handles retry when download wasn't queued for play)
            if currently_playing and currently_playing.get('filename') == filename:
                # File is currently playing (streaming), so queue it to play after download
                pending_play_queue[filename] = {
                    'playlist_entry': currently_playing.get('playlist_entry', filename),
                    'fullscreen': True,
                    'start_time': time.time(),
                    'timeout': 60
                }
        
        # Start new download
        download_to_cache(filename, silent=False)
        print(f"Retrying download: {filename}")

def download_to_cache(filename, silent=False):
    """Download an AnimThemes file to cache folder for temporary storage.
    
    Args:
        filename: Name of the file to download
        silent: If True, don't print status messages
        
    Returns:
        True if download started successfully, False otherwise
    """
    global active_downloads, cache_metadata, downloads_completed, download_progress, download_cancel_flags
    
    # Check if already downloading
    if filename in active_downloads:
        return False
    
    # Check if already in cache
    if get_cached_file_path(filename):
        return False
    
    # Check if file is in local directory
    if filename in directory_files:
        return False
    
    # Clear any previous cancel flags
    download_cancel_flags.pop(filename, None)
    
    # Create progress popup window
    if not silent:
        popup_info = create_download_popup(filename)
        download_progress[filename] = {
            'downloaded_mb': 0,
            'total_mb': 0,
            'popup': popup_info['popup'],
            'progress_bar': popup_info['progress_bar'],
            'status_label': popup_info['status_label']
        }
    else:
        # For silent downloads, just track progress without popup
        download_progress[filename] = {
            'downloaded_mb': 0,
            'total_mb': 0,
            'popup': None
        }
    
    def do_cache_download():
        global downloads_completed, cache_metadata, download_ui_update_pending, download_cancel_flags
        cancelled = False
        try:
            # Get metadata to determine season/year
            data = get_metadata(filename)
            season_str = data.get("season", "")
            
            # Parse season string (format: "Season Year", e.g., "Winter 2024")
            if season_str and season_str != "N/A":
                parts = season_str.split()
                if len(parts) >= 2:
                    season = parts[0]  # e.g., "Winter"
                    year = parts[1]    # e.g., "2024"
                else:
                    season = "Unknown"
                    year = "Unknown"
            else:
                season = "Unknown"
                year = "Unknown"
            
            # Create cache directory structure: themes_cache/year/season/
            cache_subdir = os.path.join(year, season)
            full_cache_dir = os.path.join(THEMES_CACHE_FOLDER, cache_subdir)
            os.makedirs(full_cache_dir, exist_ok=True)
            
            # Store in nested structure
            rel_path = os.path.join(cache_subdir, filename)
            dest_path = os.path.join(THEMES_CACHE_FOLDER, rel_path)
            
            # Download using core function with progress callback
            last_percent = [-1]  # Use list to allow modification in nested function
            
            def progress_callback(mb_downloaded, mb_total):
                # Update progress dict (will be read by main thread checker)
                if filename in download_progress:
                    download_progress[filename]['downloaded_mb'] = mb_downloaded
                    download_progress[filename]['total_mb'] = mb_total
                
                if not silent:
                    percent = int((mb_downloaded / mb_total) * 100)
                    # Only print every 5% to reduce spam
                    if percent != last_percent[0] and percent % 5 == 0:
                        print(f"\rCaching {filename}: {percent}% ({mb_downloaded:.1f}/{mb_total:.1f} MB)", end='', flush=True)
                        last_percent[0] = percent
            
            if not silent:
                print(f"Caching {filename}: 0%", end='', flush=True)
            
            success = _download_animethemes_file_to_path(filename, dest_path, progress_callback)
            
            # Check if cancelled
            if filename in download_cancel_flags and download_cancel_flags[filename]:
                cancelled = True
                # Delete partial file
                if os.path.exists(dest_path):
                    try:
                        os.remove(dest_path)
                    except:
                        pass
                if not silent:
                    print(f"\rDownload cancelled: {filename}" + " " * 30)
                return
            
            if not success:
                if not silent:
                    print(f"\rCache download failed: {filename}" + " " * 30)  # Clear line
                return
            
            # Get actual file size
            actual_size = os.path.getsize(dest_path)
            
            # Evict old files if needed to make room for this new file
            # Important: Do this BEFORE adding to metadata so the new file can't evict itself
            evict_cache_for_size(actual_size)
            
            # Update cache metadata with path
            cache_metadata[filename] = {
                'path': rel_path,
                'size': actual_size,
                'play_count': 0,
                'last_played': datetime.now().isoformat()
            }
            save_cache_metadata()
            
            # Update completed counter
            downloads_completed += 1
            
            if not silent:
                filesize_mb = cache_metadata[filename]['size'] / 1024 / 1024
                print(f"\rCached: {filename} ({filesize_mb:.1f} MB)" + " " * 30)  # Clear line and show final status
            
            # Set flag to indicate UI needs update (checked periodically on main thread)
            download_ui_update_pending = True
            
        except Exception as e:
            if not silent:
                print(f"Cache download error for {filename}: {e}")
        finally:
            # Remove from active downloads
            if filename in active_downloads:
                del active_downloads[filename]
            
            # Clean up cancel flag
            download_cancel_flags.pop(filename, None)
            
            # Close popup window if it exists (schedule on main thread)
            if filename in download_progress:
                popup_ref = download_progress[filename].get('popup')
                if popup_ref:
                    try:
                        root.after(0, popup_ref.destroy)
                    except:
                        pass
                del download_progress[filename]
    
    # Start download in background thread
    thread = threading.Thread(target=do_cache_download, daemon=True)
    active_downloads[filename] = thread
    thread.start()
    return True

def wait_for_download(filename, timeout=30):
    """Wait for a file download to complete.
    
    Args:
        filename: Name of the file
        timeout: Maximum seconds to wait
        
    Returns:
        True if download completed, False if timeout or not downloading
    """
    if filename not in active_downloads:
        return True  # Not downloading, so we're done
    
    thread = active_downloads[filename]
    thread.join(timeout=timeout)
    
    return filename not in active_downloads  # True if completed

def prefetch_next_themes():
    """Prefetch the next 1-5 themes based on how many downloads have completed.
    
    Progressive download logic:
    - After 0 downloads: prefetch 1 ahead
    - After 1+ downloads: prefetch 2 ahead
    - After 3+ downloads: prefetch up to 5 ahead
    """
    if not playlist.get("playlist"):
        return
    
    # Determine how many themes ahead to prefetch based on completed downloads
    if downloads_completed == 0:
        prefetch_count = 1
    elif downloads_completed < 3:
        prefetch_count = 2
    else:
        prefetch_count = 5
    
    current_idx = playlist.get("current_index", 0)
    playlist_items = playlist["playlist"]
    
    # Prefetch the next prefetch_count themes
    for i in range(1, prefetch_count + 1):
        next_idx = (current_idx + i) % len(playlist_items)
        next_entry = playlist_items[next_idx]
        next_filename = get_clean_filename(next_entry)
        
        # Check if this file needs to be cached
        if is_animethemes_stream_file(next_filename):
            # Don't download if already in local directory or cache or currently downloading
            if not check_file_availability(next_filename):
                download_to_cache(next_filename, silent=True)
    
    # Also prefetch themes from fixed lightning rounds if active
    if fixed_lightning_queue or fixed_lightning_round_playlist_data:
        # Use playlist_data if available, otherwise use queue data
        source_data = fixed_lightning_round_playlist_data if fixed_lightning_round_playlist_data else fixed_lightning_queue
        if source_data:
            next_idx = source_data.get("current_index", 0) + 1 if fixed_lightning_round_playlist_data else 0
            rounds = source_data.get("data", {}).get("rounds", []) if "data" in source_data else source_data.get("rounds", [])
            if next_idx < len(rounds):
                next_round = rounds[next_idx]
                next_filename = next_round.get("theme")
                if next_filename and is_animethemes_stream_file(next_filename) and not check_file_availability(next_filename):
                    download_to_cache(next_filename, silent=True)

def check_file_availability(filename):
    if filename in directory_files:
        return True
    if get_cached_file_path(filename):
        return True
    if filename in active_downloads:
        return False
    return False

def play_trailer(url=None):
    url = url or currently_playing.get("data", {}).get("trailer")
    if url:
        url = f"https://www.youtube.com/watch?v={url}"
        return stream_url(url, "Trailer", None, light_mode == 'clip')
    return 0

def get_stream_start_time(length):
    if fixed_current_round and fixed_current_round.get("clip_start_time"):
        return fixed_current_round.get("clip_start_time")
    if last_streamed and last_streamed[3] and "Crunchyroll" in last_streamed[3]:
        start_buffer = 0
        end_buffer = 10
    elif last_streamed and last_streamed[3] and "Netflix" in last_streamed[3]:
        start_buffer = 0
        end_buffer = 25
    else:
        start_buffer = 5
        end_buffer = 5
    if length <= light_round_length + start_buffer + end_buffer:
        return 0  # Start early if the trailer is short
    max_start = int(length - light_round_length - end_buffer)
    return random.randint(start_buffer, max_start)

def play_random_clip(data=None, queue=False, ost=False):
    if currently_streaming and not data:
        stop_stream()
        return
    if not data:
        data = currently_playing.get("data")
    url, name, channel = load_random_clips(data, ost=ost)
    if url:
        if not queue:
            return stream_url(url, name, channel)
        return url, name, channel
    else:
        if not queue:
            return 0
        return None, None, None

def load_random_clips(data=None, limit_channels=False, ost=False):
    if not data:
        data = currently_playing.get("data")
    title = get_display_title(data)
    year = int(data.get("season", "9999")[-4:])
    if ost:
        url, name, channel = get_random_anime_clip_stream_url(title, year, data, limit_channels=False, ost=True)
    else:
        url = name = channel = None
        if not is_game(data) and len(data.get("title", "")) > 1:
            url, name, channel = get_random_anime_clip_stream_url(title, year, data, limit_channels=True)
        if not url and title != get_base_title(title=title):
            url, name, channel = get_random_anime_clip_stream_url(get_base_title(title=title), year, data, limit_channels=True)
        if not url and not limit_channels:
            url, name, channel = get_random_anime_clip_stream_url(title, year, data, limit_channels=False)
    if selected_extra_metadata == "links":
        update_extra_metadata()
    return url, name, channel

def stream_clip(video_id, name, channel):
    url = f"https://www.youtube.com/watch?v={video_id}"
    if currently_streaming and currently_streaming[1] == url:
        stop_stream()
    else:
        stream_url(url, name, channel, False)

YOUTUBE_SEARCH_URL = 'https://www.googleapis.com/youtube/v3/search'
YOUTUBE_VIDEO_DETAILS_URL = 'https://www.googleapis.com/youtube/v3/videos'
youtube_api_limited = False
youtube_api_limited_count = 0
_cached_clips = {}
_cached_ost_clips = {}

def get_random_anime_clip_stream_url(anime_title, year, data, limit_channels=True, ost=False):
    global youtube_api_limited, youtube_api_limited_count
    _cached_id = f"{anime_title}-{year}"
    if not ost and _cached_id in _cached_clips and (_cached_clips[_cached_id] or limit_channels):
        valid_video_ids = _cached_clips[_cached_id]
    elif ost and _cached_id in _cached_ost_clips:
        valid_video_ids = _cached_ost_clips[_cached_id]
    else:
        youtube = build("youtube", "v3", developerKey=YOUTUBE_API_KEY)
        video_ids = None
        if limit_channels:
            query_extra = "crunchyroll"
        elif ost:
            query_extra = "anime ost"
        else:
            query_extra = "anime clip"
        if len(anime_title.split(" ")) == 1:
            query = f"{query_extra} {anime_title} {year}"
        else:
            query = f"{query_extra} {anime_title}"
        test_print(f"SEARCHING: '{query}'")
        try:
            search_response = youtube.search().list(
                q=query,
                part="id,snippet",
                type="video",
                order="relevance",
                relevanceLanguage="en",
                regionCode="US",
                maxResults=50
            ).execute()

            video_ids = [item["id"]["videoId"] for item in search_response["items"]]
            youtube_api_limited_count = 0
            test_print(len(video_ids))
        except:
            youtube_api_limited_count += 1
            if youtube_api_limited_count >= 3:
                youtube_api_limited = True
        if not video_ids:
            return None, None, None

        # Get details like duration
        details_response = youtube.videos().list(
            part="contentDetails,snippet,statistics",
            id=",".join(video_ids)
        ).execute()

        priority_video_ids = []
        valid_video_ids = []
        back_up_valid_videos = []
        for item in details_response["items"]:
            video_id = item["id"]
            duration = item["contentDetails"].get("duration", "0")
            title = item["snippet"]["title"]
            description = item["snippet"].get("description", "")
            channel_title = item["snippet"]["channelTitle"]
            
            try:
                # check aspect ratio
                thumb = (
                    item["snippet"]["thumbnails"].get("standard")
                    or item["snippet"]["thumbnails"].get("high")
                    or item["snippet"]["thumbnails"].get("medium")
                    or item["snippet"]["thumbnails"]["default"]
                )
                width = thumb.get("width")
                height = thumb.get("height")
                if width and height and width / height < 1:
                    test_print(f"[{video_id}]{title}: is short")
                    continue  # Likely a vertical video (Short)
                
                # check bad keywords
                bad_keywords = [
                    "summary", "explained", "opening", "ending", "shorts", "amv",
                    "[amv]", "trailer", "comparison", "musicvideo", "music video", 
                    "animate-it", "references", "review", "anime haul", "anime unboxing",
                    "meet the english voice of", "[sub indo]", "why you should watch ", "simulcast sampler",
                    "you should be reading", "& update", "getting a season", "in-depth",
                    "full length", "explain in", "masterpiece", "unboxing",
                    "how to watch", "op1", "op2", "op3", "op4", "op5", "op6", "op7", "op8",
                    "op9", "ed1", "ed2", "ed3", "ed4", "ed5", "ed6", "ed7", "ed8", "ed9",
                    "ranting about", "1. ", "horrible season of", "was almost perfect",
                    "anime vs manga", "10 shocking ", "everyone skipped this anime",
                    " is wicked…", "unanswered questions", "needs to address", "tráiler",
                    "release date update", "is finally here", "fun facts", "badly explaining",
                    "this manga is", "trash taste", "gigguk", "mmv", "manga release", "lyrics", "lyric",
                    "reactions", "reaction", "underrated anime is back", "is finally returning",
                    "10 differences between", "overrated!?!", "manga and anime", "film theory:",
                    "the manga that", "the anime that", "anime similar to", "should you watch",
                    "best anime of", "best watch order", "manga is so much better than the anime",
                    "everything you need to know about", "seasons ranked", "#animeedit", "they need to remake",
                    "? watch these!", "must watch", "anime you should", "anime you must", "anime you need",
                    "anime you have to", "anime you gotta", "veggietales", "reacting to", "the anime effect #",
                    "#animeexplain", "top 3", "top 5", "top 10", "top 11", "top 12", "top 13",
                    "anime mix", "english dub greeting video", "best of 20", "reacts to", "anime boston",
                    "best anime fights compilation", "best anime fight compilation", "best anime battles compilation",
                    "best anime battle compilation", "#animeindo", "first impressions"
                ]
                ost_bad_keywords = [
                    "insert song", "anime songs", "cd single", "theme song", "full album", "extended"
                ]
                game_bad_keywords = [
                    "gameplay", "let's play", "walkthrough", "opening cinematic", "game trailer", "action rpg"
                ]
                if not is_game(data):
                    bad_keywords += game_bad_keywords
                if not ost:
                    bad_keywords += ost_bad_keywords
                else:
                    bad_keywords += ["#"]

                # Filter out any bad keywords that appear in the anime title
                filtered_keywords = [kw for kw in bad_keywords if kw not in f"{anime_title.lower()} {data.get("title").lower()}"]
                if any(kw in title.lower() for kw in filtered_keywords):
                    test_print(f"[{video_id}]{title}:  bad keyword")
                    continue

                # Whole words to filter (like "op" or "ed")
                whole_word_keywords = {"op", "ed", "recap", "amv"}
                ost_whole_word_keywords = {"ost"}
                if not ost:
                    whole_word_keywords |= ost_whole_word_keywords
                def contains_whole_word(title, keywords):
                    pattern = r'\b(?:' + '|'.join(re.escape(word) for word in keywords) + r')\b'
                    return re.search(pattern, title.lower()) is not None
                if not (contains_whole_word(anime_title.lower(), whole_word_keywords) or contains_whole_word(data.get("title").lower(), whole_word_keywords)) and contains_whole_word(title, whole_word_keywords):
                    test_print(f"[{video_id}]{title}:  has a whole-word keyword")
                    continue
                
                if "movie" not in anime_title.lower() and "movie" in title.lower() and not get_format(data) == "Movie":
                    test_print(f"[{video_id}]{title}:  movie in title when not movie")
                    continue
                
                #check description
                bad_description_phrases = [" amv ", " amv.", "artista: "]
                if any(phrase in description.lower() for phrase in bad_description_phrases):
                    test_print(f"[{video_id}]{title}:  bad phrase in description")
                    continue

                # check title match
                title_okay = False
                check_description = True
                different_title_phrases = [
                    "from the creators of", "from the makers of", "by the creators of", "all it took was", "from the studio that brought you"
                ]
                
                title_to_check = title
                if channel_title in ["Crunchyroll"]:
                    if "|" in title:
                        title_to_check = title.split("|")[1].strip()
                    check_description = False
                elif any(phrase in description.lower() for phrase in different_title_phrases):
                    check_description = False
                for t in [anime_title, data.get("title"), get_base_title(title=anime_title), get_base_title(title=data.get("title"))]:
                    t_edits = [t]
                    colon_split = t.split(": ")[0]
                    if colon_split != t and len(colon_split.strip()) >= 3:
                        t_edits.append(colon_split)
                    t_edits.extend([t.replace(" ", ""), t.replace(".", ""), t.replace("-", " ")])
                    for t_edit in t_edits:
                        if title_match_score(t_edit, title_to_check) or (check_description and title_match_score(t_edit, description)):
                            title_okay = True
                            break
                    if title_okay:
                        break
                if not title_okay:
                    test_print(f"[{video_id}]{title}: title doesn't match enough")
                    continue  # skip this result
                
                if ost:
                    is_ost = False
                    for t in ["OST", "Soundtrack", "Insert Song"]:
                        if title_match_score(t, title) or title_match_score(t, description):
                            is_ost = True
                            break
                    if not is_ost:
                        test_print(f"[{video_id}]{title}: is not ost")
                        continue  # skip this result

                # check channel
                blacklisted_channels = [
                    "Reacts", "AniRecaps", "Anime Recap", "Anime Summary", "Plot Recap", "Explains", "Crunchyroll Brasil", 
                    "Explained", "Mother's Basement", "Crunchyroll: Inside Anime", "Crunchyroll TV", "It's Certified Otaku Vibes",
                    "Crunchyroll en Español", "Crunchyroll FR", "Crunchyroll India", "Crunchyroll DE", "WatchMojo", "Watch Mojo",
                    "AnimeVersa", "Crunchyroll en Español", "Netflix Jr.", "MWAMVEVO", "Tarkeus", "Gigguk", "ryuuarm", "Jent Watches"
                    "IGN Anime Club", "Albert Senpai", "AnimeSekaiStore", "ForgottenRelics", "Anuj Lama", "Garnt", " Watches"
                ]
                ost_blacklisted_channels = [
                    " - Topic"
                ]
                if not ost:
                    blacklisted_channels += ost_blacklisted_channels
                if any(blacklist in channel_title for blacklist in blacklisted_channels):
                    test_print(f"[{video_id}]{title}: bad channel")
                    continue

                # check views
                views = int(item["statistics"].get("viewCount", 0))
                if views < 500:
                    test_print(f"[{video_id}]{title}: too few views")
                    continue  # Too obscure or low-quality
                seconds = parse_iso8601_duration(duration)
                priority_channels = ["Crunchyroll", "Crunchyroll Dubs", "Netflix Anime"]
                video_data = [title, video_id, channel_title]
                if seconds >= 60 and any(priority == channel_title for priority in priority_channels):
                    less_priority_words = ["Teaser PV", "Now Available"]
                    if any(word in title for word in less_priority_words):
                        valid_video_ids.append(video_data)
                    else:
                        priority_video_ids.append(video_data)
                    continue
                elif limit_channels:
                    continue
                elif seconds > 60:
                    valid_video_ids.append(video_data)
                elif seconds >= 20:
                    back_up_valid_videos.append(video_data)
                else:
                    test_print(f"[{video_id}]{title}: too short")
            except Exception as e:
                test_print(f"error{e}")
                continue
        if not ost:
            valid_video_ids = priority_video_ids or valid_video_ids or back_up_valid_videos
        test_print(valid_video_ids)
        if not valid_video_ids:
            if ost:
                _cached_ost_clips[_cached_id] = None
            else:
                _cached_clips[_cached_id] = None
            return None, None, None
        else:
            if ost:
                _cached_ost_clips[_cached_id] = valid_video_ids
            else:
                _cached_clips[_cached_id] = valid_video_ids
    if valid_video_ids:
        if limit_channels:
            selected_title, selected_video_id, selected_channel = random.choice(valid_video_ids)
        else:
            selected_title, selected_video_id, selected_channel = random.choice(valid_video_ids[:5])
        video_url = f"https://www.youtube.com/watch?v={selected_video_id}"
        return video_url, selected_title, selected_channel
    else:
        return None, None, None
    
def title_match_score(anime_title, video_title):
    GENERIC_WORDS = {
        "the", "a", "an", "of", "and", "in", "to", "for", "with", "on",
        "season", "part", "new", "as"
    }
    # Common phrases that appear in many anime titles and shouldn't count as unique matches
    COMMON_PHRASES = {
        "daily life", "life of", "story of", "tale of", "adventures of",
        "chronicles of", "saga of", "legend of", "world of"
    }
    
    # Special handling for very short anime titles (1-2 characters)
    # These need exact word boundary matches to avoid false positives
    anime_stripped = anime_title.strip()
    if len(anime_stripped) <= 2:
        # For single/double character titles like "X" or "91", require exact word match
        # Use word boundaries to ensure it's standalone, not part of another word
        pattern = r'\b' + re.escape(anime_stripped) + r'\b'
        if re.search(pattern, video_title, re.IGNORECASE):
            return True
        return False
    
    def clean_words(text, exclude_generic=True):
        words = [
            word.strip("|『[]×.,!?:;\"'").lower()
            for word in text.lower().split()
        ]
        if exclude_generic:
            words = [w for w in words if w not in GENERIC_WORDS]
        return words

    anime_words = clean_words(anime_title, True)
    anime_words_count = clean_words(anime_title)
    video_words = clean_words(video_title, True)

    # Filter case: Video title contains "from the director of <Anime Title>" which refers to a DIFFERENT work.
    lowered_full = video_title.lower()
    phrase_key = "from the director of"
    if phrase_key in lowered_full:
        # Build regex to capture the portion after the phrase up to common separators
        # (dash, pipe, colon, parentheses start, end of string)
        # Example: "From the director of Attack on Titan | New Sci-Fi Original" -> captures "Attack on Titan"
        pattern = re.compile(r"from the director of\s+([^-|:()]+)", re.IGNORECASE)
        spans = []
        for m in pattern.finditer(video_title):
            span_words = clean_words(m.group(1), False)
            spans.append((m.span(1), span_words))
        if spans:
            # Count total appearances of anime words in entire title
            video_all_tokens_no_generic = clean_words(video_title, True)
            anime_set = set(anime_words)
            # Build a map of indices of tokens in spans
            tokens_full = [w.strip("|『[]×.,!?:;\"'").lower() for w in video_title.lower().split()]
            # For simplicity: check raw substring presence outside phrase first.
            outside_text = lowered_full
            for sspan, _w in spans:
                start, end = sspan
                outside_text = outside_text[:start].replace(anime_title.lower(), "") + outside_text[end:].replace(anime_title.lower(), "")
            # If after removing span regions the anime title (as a contiguous substring ignoring case) no longer appears,
            # and all anime words appear inside one span, treat as non-match.
            anime_inline = anime_title.lower()
            appears_outside = anime_inline in outside_text
            # Also ensure the span actually contains all required anime words (order-insensitive) to avoid false negatives.
            span_contains_all = any(anime_set.issubset(set(words)) for _, words in spans)
            if span_contains_all and not appears_outside:
                return False

    # Try to match all anime title words in order in the video title
    i = 0
    matched_words = []
    if len(anime_words_count) < 3:
        min_match = len(anime_words_count)
    else:
        min_match = min(5, max(1, len(anime_words_count) // 2 + len(anime_words_count) % 2))
    
    for word in video_words:
        if i < len(anime_words) and word == anime_words[i]:
            matched_words.append(word)
            i += 1
            if i >= min_match:
                # Check if we've only matched a common phrase
                matched_text = " ".join(matched_words)
                is_only_common_phrase = any(phrase in matched_text for phrase in COMMON_PHRASES)
                
                # If we've only matched a common phrase, require at least one more unique word
                if is_only_common_phrase and i < len(anime_words):
                    continue  # Keep looking for more matches
                
                return True
        else:
            i = 0
            matched_words = []
    return False

def parse_iso8601_duration(duration):
    match = re.match(r'PT(?:(\d+)M)?(?:(\d+)S)?', duration)
    if not match:
        return 0
    minutes = int(match.group(1)) if match.group(1) else 0
    seconds = int(match.group(2)) if match.group(2) else 0
    return minutes * 60 + seconds

test_printing = False
def test_print(text):
    if test_printing:
        print(text)

edge_overlay = None
def toggle_outer_edge_overlay(destroy=False, pixels=65, color="black"):
    global edge_overlay

    if destroy:
        if edge_overlay:
            edge_overlay.destroy()
            edge_overlay = None
        return

    if edge_overlay:
        edge_overlay.lift()
        edge_overlay.attributes("-topmost", True)
        return

    # Create the overlay window
    edge_overlay = tk.Toplevel()
    edge_overlay.overrideredirect(True)
    edge_overlay.attributes("-topmost", True)

    screen_width = edge_overlay.winfo_screenwidth()
    screen_height = edge_overlay.winfo_screenheight()
    edge_overlay.geometry(f"{screen_width}x{pixels}+0+{screen_height - pixels}")

    # Background frame (bottom only)
    frame = tk.Frame(edge_overlay, bg=color)
    frame.pack(fill="both", expand=True)

